#include <bits/stdc++.h>
using namespace std;
int l,r,s;
bool zs(int x) {
	if(x<=1) {
		return 0;
	}
	for(int i=2; i*i<=x; i++) {
		if(x%i==0) {
			return 0;
		}
	}
	return 1;
}
int main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>l>>r;
	if(l>r) {
		swap(l,r);
	}
	for(int i=l; i<=r; i++) {
		if(zs(i)) {
			s++;
		}
	}
	cout<<s;
	return 0;
}
